// Human-in-the-loop용 후보 정규화 및 '후보별 편집' 프롬프트 생성
// 중요: 이 단계에서 AI는 후보를 선택하거나 탈락시키지 않습니다.

const request = $('A0. Webhook - 뉴스레터 후보 초안 조회').first().json.body || {};
const newsletterRows = $('A2. Google Sheets - newsletter_research 후보 조회').all().map(x => x.json || {});
const researchRows = $('A3. Google Sheets - research_results 후보 조회').all().map(x => x.json || {});

function txt(v){ return v === null || v === undefined ? '' : String(v).trim(); }
function truthy(v){
  if (v === true || v === 1) return true;
  return ['true','1','y','yes','예','o'].includes(txt(v).toLowerCase());
}
function parseDate(v){ const d = new Date(v || ''); return isNaN(d.getTime()) ? null : d; }
function parseJson(v){
  if (v && typeof v === 'object') return v;
  try { return v ? JSON.parse(v) : {}; } catch { return {}; }
}
function urls(v){
  if (Array.isArray(v)) return [...new Set(v.map(txt).filter(x => /^https?:\/\//i.test(x)))].slice(0,4);
  return [...new Set(txt(v).split(/[\n,]+/).map(x=>x.trim()).filter(x => /^https?:\/\//i.test(x)))].slice(0,4);
}
function getDocText(obj){
  const chunks=[];
  const walk=(x)=>{
    if(!x || typeof x !== 'object') return;
    if(x.textRun && typeof x.textRun.content === 'string') chunks.push(x.textRun.content);
    for(const v of Object.values(x)){
      if(Array.isArray(v)) v.forEach(walk);
      else if(v && typeof v === 'object') walk(v);
    }
  };
  walk(obj);
  return chunks.join('').replace(/\r/g,'\n').replace(/\n{3,}/g,'\n\n').trim().slice(0,1200);
}

const days = Math.max(1, Math.min(30, Number(request.days || 7)));
const maxPerSection = Math.max(1, Math.min(10, Number(request.max_per_section || 6)));
const now = new Date();
const from = new Date(now.getTime() - days * 86400000);
const periodStart = from.toISOString().slice(0,10);
const periodEnd = now.toISOString().slice(0,10);
function inWindow(v){ const d=parseDate(v); return !d || (d >= from && d <= now); }

const external = newsletterRows
  .filter(r => inWindow(r.collected_at || r.generated_at || r.created_at))
  .map((r,i)=>({
    candidate_id: txt(r.item_id || `NLR-${i+1}`),
    section: txt(r.section).toUpperCase(),
    title: txt(r.title),
    summary: txt(r.summary).slice(0,900),
    implication: txt(r.implication).slice(0,500),
    source_urls: urls(r.source_urls),
    priority: Number(r.priority || 50),
    evidence_level: txt(r.evidence_level || 'MEDIUM'),
    target: txt(r.target),
    keyword: txt(r.keyword)
  }))
  .filter(x => ['CLIENT_WATCH','BUSINESS_WORK','PEOPLE_CULTURE'].includes(x.section))
  .filter(x => x.title || x.summary)
  .sort((a,b)=>b.priority-a.priority);

const internal = researchRows
  .filter(r => inWindow(r.created_at || r.generated_at || r.requested_at))
  .filter(r => r.newsletter_candidate === undefined || r.newsletter_candidate === '' || truthy(r.newsletter_candidate))
  .map((r,i)=>{
    const raw=parseJson(r.raw_json || r.report_json || r.result_json);
    const eb=raw.executive_brief || {};
    // research_results 시트에는 원문 URL이 'source_urls'라는 별도 컬럼으로 저장되지 않고,
    // raw_json(=raw) 안의 source_summaries 배열(각 항목에 title/url)에 들어있다.
    // (뉴스 크롤링 2단계 워크플로우의 '8. Code - AI 응답 JSON 정리' 참고)
    // 예전 코드가 존재하지 않는 raw.source_urls를 찾고 있어서 내부 리서치 결과에 링크가 비어 있었다.
    return {
      candidate_id: txt(r.research_id || `RES-${i+1}`),
      section:'RESEARCH_ON_INSIGHT',
      title: txt(r.keyword || raw.keyword || `내부 리서치 ${i+1}`),
      summary: txt(r.one_line_conclusion || eb.one_line_conclusion).slice(0,900),
      implication: txt(eb.relevance_to_organization || eb.recommended_action).slice(0,500),
      source_urls: urls(r.source_urls || raw.source_urls || (Array.isArray(raw.source_summaries) ? raw.source_summaries.map(s => s && s.url) : [])),
      priority: Number(r.newsletter_priority || 50),
      evidence_level:'INTERNAL',
      target:'', keyword:txt(r.keyword || raw.keyword)
    };
  })
  .filter(x => x.title || x.summary)
  .sort((a,b)=>b.priority-a.priority);

const groupedCandidates = {
  client_watch: external.filter(x=>x.section==='CLIENT_WATCH').slice(0,maxPerSection),
  research_on_insight: internal.slice(0,maxPerSection),
  business_work: external.filter(x=>x.section==='BUSINESS_WORK').slice(0,maxPerSection),
  people_culture: external.filter(x=>x.section==='PEOPLE_CULTURE').slice(0,maxPerSection)
};
const candidateCount = Object.values(groupedCandidates).reduce((s,a)=>s+a.length,0);
if(!candidateCount) throw new Error(`최근 ${days}일간 웹에 표시할 뉴스레터 후보가 없습니다.`);

let docJson={};
try { docJson=$('A1. Google Docs - 회사 맥락 읽기').first().json || {}; } catch {}
const companyContext = getDocText(docJson) || '회사 맥락 문서를 불러오지 못했습니다. 후보에 있는 사실만 사용합니다.';

const prompt = `너는 BPO사업본부 주간 뉴스레터의 후보 문구 편집자다.
아래 후보를 웹페이지에 모두 보여줘야 한다. 후보를 선택·삭제·통합하거나 순서를 임의로 바꾸지 마라.
각 candidate_id마다 정확히 하나의 편집 결과를 만들고 candidate_id를 그대로 복사하라.
관리자가 웹에서 후보를 검토한 뒤 섹션별 최종 1건을 선택하므로, 너는 선택 판단을 하지 않는다.

[편집 원칙 - 1차 독자는 CL4 이상 보직자(센터장·그룹장·사업부장·임원)다]
- 바쁜 보직자가 이 항목만 읽고도 핵심과 맥락을 파악해 회의나 의사결정에 참고할 수 있는 수준으로 다듬는다. 짧게 쓰되 알맹이(수치·시점·구체적 근거)는 절대 빼지 않는다.
- title: 원문 제목을 그대로 복사하지 말고 핵심을 15~25자 내외로 다시 쓴다.
- summary: 후보의 구체적 숫자·고유명사·행동을 살려 2~3문장으로 정리한다. 후보에 이미 있는 구체성(수치·시점·기업명 등)을 절대 생략하거나 뭉뚱그리지 않는다.
- implication: CLIENT WATCH, RESEARCH ON INSIGHT, BUSINESS & WORK, PEOPLE & CULTURE 네 섹션 모두 반드시 작성한다. "~할 기회입니다" 같은 상투적 한 줄로 끝내지 말고, 이 사안이 BPO사업본부 운영·사업에 어떤 의미인지와 보직자가 무엇을 검토·논의해야 하는지를 담아 1~2문장으로 정리한다. PEOPLE & CULTURE의 implication은 채용·유지·조직문화·세대 간 소통·복리후생 설계 관점에서 작성한다. 후보에 이미 implication/organization_view가 있다면 절대 비우거나 삭제하지 말고, 문장을 다듬어 최대한 살린다.
- executive_brief.headline과 summary는 후보 중 중요도가 가장 높아 보이는 이슈 1~2개를 중심으로, 보직자가 이번 주 가장 먼저 알아야 할 것이 무엇인지 드러나게 작성한다. 관리자가 최종 후보를 고른 뒤 다시 다듬을 임시 초안이니 지금은 후보 전체를 보고 가장 비중 있어 보이는 것 위주로 작성하면 된다.
- 후보에 없는 사실은 절대 추가하지 않는다.
- source_urls는 출력하지 않는다. 시스템이 candidate_id를 기준으로 원본 URL을 다시 붙인다.
- 반드시 JSON 객체만 출력한다.

[회사 업무 맥락 - 우선순위와 문체 참고용]
${companyContext}

[기간]
${periodStart} ~ ${periodEnd}

[후보]
${JSON.stringify(groupedCandidates)}

[출력 형식]
{
  "issue_title":"후보 검토용 주간 브리핑 제목",
  "executive_brief":{"headline":"후보 전체를 관통하는 임시 헤드라인","summary":"관리자가 선택 후 수정할 수 있는 임시 요약"},
  "sections":{
    "client_watch":[{"candidate_id":"","title":"","summary":"","implication_label":"시사점","implication":""}],
    "research_on_insight":[{"candidate_id":"","title":"","summary":"","implication_label":"시사점","implication":""}],
    "business_work":[{"candidate_id":"","title":"","summary":"","implication_label":"시사점","implication":""}],
    "people_culture":[{"candidate_id":"","title":"","summary":"","implication_label":"시사점","implication":""}]
  },
  "people_culture_view":"후보 전체를 본 임시 종합 코멘트",
  "editor_note":"Human in the loop 후보 초안"
}`;

return [{json:{
  issue_id:`DRAFT-${periodEnd.replace(/-/g,'')}-${Math.random().toString(36).slice(2,7).toUpperCase()}`,
  generated_at:now.toISOString(), period_start:periodStart, period_end:periodEnd,
  grouped_candidates:groupedCandidates, candidate_count:candidateCount,
  editor_prompt:prompt
}}];

// AI 결과를 파싱하되 후보 누락·URL 환각을 차단하고 웹페이지 구조로 변환
const base=$('A4. Code - 후보 정규화 + 후보별 편집 프롬프트').first().json;
const raw=$json.text || $json.output || $json.response || $json.content || $json.result || '';
function txt(v){return v===null||v===undefined?'':String(v).trim();}
function arr(v){return Array.isArray(v)?v:[];}
function parse(v){
  if(v && typeof v==='object') return v;
  let s=String(v||'').replace(/^```json\s*/i,'').replace(/^```\s*/,'').replace(/```$/,'').trim();
  const a=s.indexOf('{'), b=s.lastIndexOf('}'); if(a>=0&&b>=a) s=s.slice(a,b+1);
  s=s.replace(/,\s*([}\]])/g,'$1');
  try{return JSON.parse(s);}catch{return {};}
}
const ai=parse(raw);
const groups=base.grouped_candidates || {};

function normalizeGroup(key, hasImplication){
  const originals=arr(groups[key]);
  const aiItems=arr(ai.sections?.[key]);
  const byId=new Map(aiItems.map(x=>[txt(x.candidate_id),x]));
  return originals.map((o,idx)=>{
    const x=byId.get(txt(o.candidate_id)) || {};
    return {
      title:txt(x.title || o.title || `후보 ${idx+1}`),
      summary:txt(x.summary || o.summary),
      implication_label:hasImplication ? txt(x.implication_label || '시사점') : '',
      implication:hasImplication ? txt(x.implication || o.implication) : '',
      source_urls:arr(o.source_urls).map(txt).filter(u=>/^https?:\/\//i.test(u)).slice(0,4)
    };
  }).filter(x=>x.title || x.summary);
}
const sections={
  client_watch:normalizeGroup('client_watch',true),
  research_on_insight:normalizeGroup('research_on_insight',true),
  business_work:normalizeGroup('business_work',true),
  people_culture:normalizeGroup('people_culture',true),
  people_culture_view:txt(ai.people_culture_view)
};
const newsletter={
  newsletter_title:'Research On Weekly',
  issue_title:txt(ai.issue_title || `${base.period_start} ~ ${base.period_end} 주간 브리핑`),
  period:`${base.period_start} ~ ${base.period_end}`,
  executive_brief:{
    headline:txt(ai.executive_brief?.headline || '이번 주 후보 자료 검토'),
    summary:txt(ai.executive_brief?.summary || '섹션별 후보를 검토하고 최종 발송 항목을 남겨주세요.')
  },
  sections,
  editor_note:txt(ai.editor_note || 'Human in the loop 후보 초안')
};
return [{json:{
  success:true, mode:'HUMAN_REVIEW', issue_id:base.issue_id,
  generated_at:base.generated_at, period_start:base.period_start, period_end:base.period_end,
  candidate_count:base.candidate_count, newsletter
}}];

// 웹에서 관리자가 승인한 뉴스레터를 검증하고 예약 데이터로 정규화
const data=$json.body || $json;
const input=data.newsletter || {};
function txt(v){return v===null||v===undefined?'':String(v).trim();}
function arr(v){return Array.isArray(v)?v:[];}
function safeUrls(v){return arr(v).map(txt).filter(u=>/^https?:\/\//i.test(u)).slice(0,4);}
function cleanItem(x,hasImplication){
  return {
    title:txt(x?.title), summary:txt(x?.summary),
    implication_label:hasImplication?txt(x?.implication_label||'시사점'):'',
    implication:hasImplication?txt(x?.implication):'',
    source_urls:safeUrls(x?.source_urls)
  };
}
const warnings=[];
// 웹 화면(HITL 검토)에서 관리자가 섹션별로 남겨둔 항목을 '전부' 예약한다.
// 한 섹션에 비정상적으로 많은 항목이 남아있을 경우를 대비해 섹션당 최대 6개(웹 화면의 최대 노출 개수와 동일)로만 안전장치를 둔다.
const MAX_PER_SECTION=6;
function selectItems(key,hasImplication){
  const valid=arr(input.sections?.[key]).map(x=>cleanItem(x,hasImplication)).filter(x=>x.title||x.summary);
  if(valid.length>MAX_PER_SECTION) warnings.push(`${key}: ${valid.length}개 중 상위 ${MAX_PER_SECTION}개만 발송에 포함했습니다.`);
  return valid.slice(0,MAX_PER_SECTION);
}
const sections={
  client_watch:selectItems('client_watch',true),
  research_on_insight:selectItems('research_on_insight',true),
  business_work:selectItems('business_work',true),
  people_culture:selectItems('people_culture',true),
  people_culture_view:txt(input.sections?.people_culture_view)
};
const selectedCount=['client_watch','research_on_insight','business_work','people_culture'].reduce((s,k)=>s+sections[k].length,0);
if(!selectedCount) throw new Error('최종 발송 항목이 없습니다. 섹션별로 최소 1개 후보를 남겨주세요.');

const now=new Date();
// 다음 월요일 08:00 KST를 UTC ISO로 계산
const kstNow=new Date(now.getTime()+9*3600000);
const day=kstNow.getUTCDay();
const daysUntilMonday=(8-day)%7 || 7;
const targetUtcMs=Date.UTC(kstNow.getUTCFullYear(),kstNow.getUTCMonth(),kstNow.getUTCDate()+daysUntilMonday,8,0,0)-9*3600000;
const scheduledFor=new Date(targetUtcMs).toISOString();
const period=txt(input.period);
const periodEnd=txt(data.period_end || input.period_end || (period.match(/(20\d{2}-\d{2}-\d{2})\s*$/)||[])[1] || now.toISOString().slice(0,10));
const periodStart=txt((period.match(/^(20\d{2}-\d{2}-\d{2})/)||[])[1]);
const newsletter={
  newsletter_title:'Research On Weekly',
  issue_title:txt(input.issue_title || `${periodEnd} 주간 브리핑`),
  period:period || `${periodStart} ~ ${periodEnd}`,
  executive_brief:{headline:txt(input.executive_brief?.headline),summary:txt(input.executive_brief?.summary)},
  sections,
  editor_note:txt(input.editor_note)
};
const recipient=txt(data.recipient || 'bpo.dsplan1@gmail.com');
if(!recipient) throw new Error('수신 이메일이 없습니다.');
return [{json:{
  issue_id:`NLQ-${periodEnd.replace(/-/g,'')}-${Math.random().toString(36).slice(2,7).toUpperCase()}`,
  generated_at:now.toISOString(), queued_at:now.toISOString(), scheduled_for:scheduledFor,
  period_start:periodStart, period_end:periodEnd, recipient,
  selected_count:selectedCount, warnings, newsletter,
  subject:txt(data.subject || `[Research On Weekly] ${periodEnd} 주간 뉴스레터`)
}}];

// =============================================
// 상세 HTML 템플릿 렌더링
// =============================================

const data = $json;
const nl = data.newsletter || {};
const sections = nl.sections || {};

function e(v) {
  return String(v ?? '')
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#039;');
}
function p(v) {
  return e(v)
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\n/g,'<br>');
}
// 인스타그램/틱톡/X/Threads 등은 자기 페이지가 다른 사이트의 iframe 안에 뜨는 걸 서버 차원에서 막는다.
// 이런 도메인만 새 탭으로 열고, 그 외 일반 기사 링크는 관리자 미리보기(iframe) 안에서 그대로 열리게 둔다.
const NEW_TAB_DOMAINS = ['instagram.com','tiktok.com','x.com','twitter.com','threads.net','facebook.com','youtube.com'];
function needsNewTab(url) {
  try { const host = new URL(url).hostname.replace(/^www\./, ''); return NEW_TAB_DOMAINS.some(d => host === d || host.endsWith('.' + d)); }
  catch (e) { return false; }
}
function sourceLinks(urls = []) {
  const safe = Array.isArray(urls) ? urls.filter(Boolean).slice(0,4) : [];
  if (!safe.length) return '';
  const links = safe.map((url, idx) => {
    const attr = needsNewTab(url) ? ' target="_blank" rel="noopener noreferrer"' : '';
    return `<a href="${e(url)}"${attr} style="color:#64748B;text-decoration:underline;">원문 ${idx+1}</a>`;
  }).join('&nbsp;&nbsp;');
  return `<div style="margin-top:13px;font-size:12px;line-height:19px;color:#64748B;">${links}</div>`;
}
function divider() {
  return `<tr><td style="padding:0 40px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td style="border-top:1px solid #E5E7EB;font-size:1px;line-height:1px;">&nbsp;</td></tr></table></td></tr>`;
}
function itemBlock(item, culture = false, last = false) {
  const bg = culture ? '#F2F7F4' : '#EEF3FF';
  const labelColor = culture ? '#2F6B4F' : '#274690';
  const textColor = culture ? '#3F5B4C' : '#35415E';
  // 모든 섹션(PEOPLE & CULTURE 포함)에서 시사점이 있으면 박스를 그린다.
  // (예전에는 PEOPLE & CULTURE는 무조건 숨기고 섹션 전체 종합 코멘트만 보여줬으나,
  //  CL4 이상 보직자용으로 항목별 조직 운영 시사점을 반드시 채우도록 프롬프트를 바꿨다.)
  const implicationHtml = item.implication ? `
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-top:16px;border-collapse:collapse;">
      <tr>
        <td style="padding:15px 17px;background-color:${bg};">
          <div style="font-size:12px;line-height:18px;font-weight:bold;color:${labelColor};">${e(item.implication_label || '시사점')}</div>
          <div style="margin-top:5px;font-size:14px;line-height:24px;color:${textColor};">${p(item.implication)}</div>
        </td>
      </tr>
    </table>` : '';
  const block = `
<tr>
  <td style="padding:26px 40px ${last ? '32px' : '26px'};">
    <div style="font-size:20px;line-height:30px;font-weight:bold;color:#111827;">
      ${e(item.title)}
    </div>
    <div style="margin-top:12px;font-size:15px;line-height:26px;color:#3F4652;">
      ${p(item.summary)}
    </div>
    ${implicationHtml}
    ${sourceLinks(item.source_urls)}
  </td>
</tr>`;
  return block + (last ? '' : divider());
}
function cultureViewBlock(view) {
  if (!view) return '';
  return `
<tr>
  <td style="padding:0 40px 32px;">
