function sectionBlock(no, code, title, description, items, culture = false, trailingView = '') {
  if (!Array.isArray(items) || !items.length) return '';
  const hasTrailing = culture && !!trailingView;
  const lastIdx = items.length - 1;
  const itemsHtml = items
    .map((x, i) => itemBlock(x, culture, hasTrailing ? false : i === lastIdx))
    .join('');
  const trailingHtml = hasTrailing ? cultureViewBlock(trailingView) : '';
  return `
<tr>
  <td style="padding:26px 40px 12px;background-color:#F8FAFC;border-top:1px solid #E5E7EB;">
    <div style="font-size:12px;line-height:18px;letter-spacing:1.2px;font-weight:bold;color:#274690;">${no} · ${e(code)}</div>
