const rows=$input.all().map(x=>x.json||{});
const now=Date.now();
function txt(v){return v===null||v===undefined?'':String(v).trim();}
function parse(v){try{return v&&typeof v==='object'?v:JSON.parse(v||'{}');}catch{return {};}}
const seen=new Set();
const out=[];
for(const r of rows){
  if(txt(r.status).toUpperCase()!=='QUEUED') continue;
  const issueId=txt(r.issue_id); if(!issueId || seen.has(issueId)) continue;
  const wrap=parse(r.newsletter_json);
  const delivery=wrap.delivery || {};
  const when=new Date(delivery.scheduled_for || r.generated_at || 0).getTime();
  if(Number.isFinite(when) && when>now) continue;
  const html=txt(r.newsletter_html); if(!html) continue;
  seen.add(issueId);
  out.push({json:{
    issue_id:issueId,
    generated_at:txt(r.generated_at),
    period_start:txt(r.period_start), period_end:txt(r.period_end),
    subject:txt(r.subject), issue_title:txt(r.issue_title),
    newsletter_html:html, newsletter_json:txt(r.newsletter_json),
    editor_note:txt(r.editor_note), research_count:r.research_count,
    recipient:txt(delivery.recipient || 'bpo.dsplan1@gmail.com')
  }});
}
return out;

